// --- Models ---

class User {
  final String id;
  final String name;
  final String email;

  User({required this.id, required this.name, required this.email});

  factory User.fromJson(Map<String, dynamic> json) {
    return User(
      id: json['id'] as String,
      name: json['name'] as String,
      email: json['email'] as String,
    );
  }

  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'name': name,
      'email': email,
    };
  }
}

class Item {
  final String id;
  final String title;
  final String description;

  Item({required this.id, required this.title, required this.description});

  factory Item.fromJson(Map<String, dynamic> json) {
    return Item(
      id: json['id'] as String,
      title: json['title'] as String,
      description: json['description'] as String,
    );
  }

  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'title': title,
      'description': description,
    };
  }
}

// --- API Client ---

class ApiClient {
  static const String _baseUrl = 'https://api.example.com';
  static const String _tokenKey = 'auth_token';

  String? _authToken;

  ApiClient() {
    _loadAuthToken();
  }

  Future<void> _loadAuthToken() async {
    final prefs = await SharedPreferences.getInstance();
    _authToken = prefs.getString(_tokenKey);
  }

  Future<void> _saveAuthToken(String token) async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString(_tokenKey, token);
    _authToken = token;
  }

  Future<void> _clearAuthToken() async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.remove(_tokenKey);
    _authToken = null;
  }

  Map<String, String> _getHeaders({bool requireAuth = true}) {
    final Map<String, String> headers = {
      'Content-Type': 'application/json',
      'Accept': 'application/json',
    };
    if (requireAuth && _authToken != null) {
      headers['Authorization'] = 'Bearer $_authToken';
    }
    return headers;
  }

  // --- Authentication ---

  bool isAuthenticated() {
    return _authToken != null;
  }

  Future<String> login(String username, String password) async {
    final url = Uri.parse('$_baseUrl/auth/login');
    final response = await http.post(
      url,
      headers: _getHeaders(requireAuth: false),
      body: jsonEncode({'username': username, 'password': password}),
    );

    if (response.statusCode == 200) {
      final data = jsonDecode(response.body);
      final token = data['token'] as String;
      await _saveAuthToken(token);
      return token;
    } else {
      final errorData = jsonDecode(response.body);
      throw Exception('Failed to login: ${errorData['message'] ?? response.reasonPhrase}');
    }
  }

  Future<void> logout() async {
    await _clearAuthToken();
    // Optionally, call a logout endpoint if your API requires it
    // final url = Uri.parse('$_baseUrl/auth/logout');
    // await http.post(url, headers: _getHeaders());
  }

  // --- User Profile Retrieval ---

  Future<User> getProfile() async {
    if (!isAuthenticated()) {
      throw Exception('Not authenticated. Please log in first.');
    }

    final url = Uri.parse('$_baseUrl/profile');
    final response = await http.get(
      url,
      headers: _getHeaders(),
    );

    if (response.statusCode == 200) {
      final data = jsonDecode(response.body);
      return User.fromJson(data);
    } else if (response.statusCode == 401) {
      await _clearAuthToken(); // Token might be expired or invalid
      throw Exception('Unauthorized. Please log in again.');
    } else {
      final errorData = jsonDecode(response.body);
      throw Exception('Failed to fetch profile: ${errorData['message'] ?? response.reasonPhrase}');
    }
  }

  // --- Data Synchronization (e.g., fetching a list of items) ---

  Future<List<Item>> getItems() async {
    if (!isAuthenticated()) {
      throw Exception('Not authenticated. Please log in first.');
    }

    final url = Uri.parse('$_baseUrl/data/items');
    final response = await http.get(
      url,
      headers: _getHeaders(),
    );

    if (response.statusCode == 200) {
      final List<dynamic> data = jsonDecode(response.body);
      return data.map((json) => Item.fromJson(json)).toList();
    } else if (response.statusCode == 401) {
      await _clearAuthToken(); // Token might be expired or invalid
      throw Exception('Unauthorized. Please log in again.');
    } else {
      final errorData = jsonDecode(response.body);
      throw Exception('Failed to fetch items: ${errorData['message'] ?? response.reasonPhrase}');
    }
  }

  // Example of a POST request for data synchronization (e.g., adding an item)
  Future<Item> createItem(Item newItem) async {
    if (!isAuthenticated()) {
      throw Exception('Not authenticated. Please log in first.');
    }

    final url = Uri.parse('$_baseUrl/data/items');
    final response = await http.post(
      url,
      headers: _getHeaders(),
      body: jsonEncode(newItem.toJson()),
    );

    if (response.statusCode == 201) { // 201 Created
      final data = jsonDecode(response.body);
      return Item.fromJson(data);
    } else if (response.statusCode == 401) {
      await _clearAuthToken();
      throw Exception('Unauthorized. Please log in again.');
    } else {
      final errorData = jsonDecode(response.body);
      throw Exception('Failed to create item: ${errorData['message'] ?? response.reasonPhrase}');
    }
  }
}

